mapper.select:
SELECT c.CAL_SN, c.EVENT_NM, c.EVENT_BGNG_DT, c.EVENT_END_DT, c.PRVT_YN FROM TB_CALENDAR c WHERE 1=1 AND DEL_YN = 0 -- 날짜 범위: [searchStartDate, endExclusive)
-- 일정 시작 < 검색 종료 AND 검색 시작 <= 일정 종료 일때 참 AND(c.EVENT_BGNG_DT < #{searchEndDate}) AND(#{searchStartDate} <= c.EVENT_END_DT)
-- switch문처럼 동작함 위에서부터 조건 걸리는거 하나만 실행. AND c.PRVT_YN = 1 AND c.USER_SN = #{userSn}
AND c.PRVT_YN = 0 AND c.COHORT_SN = #{cohortSn}
-- 전체 조회의 경우 AND ( (c.PRVT_YN = 1 AND c.USER_SN = #{userSn}) OR (c.PRVT_YN = 0 AND c.COHORT_SN = #{cohortSn}) )
ORDER BY CAL_SN ASC -- EVENT_REG_DT ASC

mapper.update:
UPDATE TB_CALENDAR
SET VIEW_CNT = VIEW_CNT + 1
WHERE CAL_SN = #{calSn}

mapper.select:
SELECT c.CAL_SN, c.EVENT_BGNG_DT, c.EVENT_END_DT, c.EVENT_NM, c.EVENT_REG_DT, c.PRVT_YN, c.VIEW_CNT, u.USER_NM FROM TB_CALENDAR c LEFT JOIN TB_USER u ON u.USER_SN = c.USER_SN WHERE 1=1 AND DEL_YN = 0
-- switch문처럼 동작함 위에서부터 조건 걸리는거 하나만 실행. AND c.PRVT_YN = 1 AND c.USER_SN = #{userSn}
AND c.PRVT_YN = 0 AND c.COHORT_SN = #{cohortSn}
-- 전체 조회의 경우 AND ((c.PRVT_YN = 1 AND c.USER_SN = #{userSn}) OR (c.PRVT_YN = 0 AND c.COHORT_SN = #{cohortSn}) )
ORDER BY CAL_SN DESC -- EVENT_REG_DT ASC
